    fp I_kp_junc = Fjunc * gkp * kp_kp * (initvalu_39 - ek);
    fp I_kp_sl   = Fsl   * gkp * kp_kp * (initvalu_39 - ek);
    fp I_kp = I_kp_junc + I_kp_sl;

    fp xtoss = 1.0f / (1.0f + exp(-(initvalu_39 + 3.0f) / 15.0f));
    fp ytoss = 1.0f / (1.0f + exp((initvalu_39 + 33.5f) / 10.0f));
    fp rtoss = 1.0f / (1.0f + exp((initvalu_39 + 33.5f) / 10.0f));
    fp tauxtos = 9.0f / (1.0f + exp((initvalu_39 + 3.0f) / 15.0f)) + 0.5f;
    fp tauytos = 3.0e3f / (1.0f + exp((initvalu_39 + 60.0f) / 10.0f)) + 30.0f;
    fp taurtos = 2800.0f / (1.0f + exp((initvalu_39 + 60.0f) / 10.0f)) + 220.0f;
    finavalu[b + 7]  = (xtoss - initvalu_8) / tauxtos;
    finavalu[b + 8]  = (ytoss - initvalu_9) / tauytos;
    finavalu[b + 39] = (rtoss - initvalu_40) / taurtos;
    fp I_tos = GtoSlow * initvalu_8 * (initvalu_9 + 0.5f * initvalu_40) * (initvalu_39 - ek);

    fp tauxtof = 3.5f * exp(-initvalu_39 * initvalu_39 / 30.0f / 30.0f) + 1.5f;
    fp tauytof = 20.0f / (1.0f + exp((initvalu_39 + 33.5f) / 10.0f)) + 20.0f;
    finavalu[b + 9]  = (xtoss - initvalu_10) / tauxtof;
    finavalu[b + 10] = (ytoss - initvalu_11) / tauytof;
    fp I_tof = GtoFast * initvalu_10 * initvalu_11 * (initvalu_39 - ek);
    fp I_to = I_tos + I_tof;

    fp aki = 1.02f / (1.0f + exp(0.2385f * (initvalu_39 - ek - 59.215f)));
    fp bki = (0.49124f * exp(0.08032f * (initvalu_39 + 5.476f - ek)) + exp(0.06175f * (initvalu_39 - ek - 594.31f)))
           / (1.0f + exp(-0.5143f * (initvalu_39 - ek + 4.753f)));
    fp kiss = aki / (aki + bki);
    fp I_ki = 0.9f * sqrt(Ko / 5.4f) * kiss * (initvalu_39 - ek);

    fp I_ClCa_junc = Fjunc * GClCa / (1.0f + KdClCa / initvalu_36) * (initvalu_39 - ecl);
    fp I_ClCa_sl   = Fsl   * GClCa / (1.0f + KdClCa / initvalu_37) * (initvalu_39 - ecl);
    fp I_ClCa = I_ClCa_junc + I_ClCa_sl;
    fp I_Clbk = GClB * (initvalu_39 - ecl);

    fp dss = 1.0f / (1.0f + exp(-(initvalu_39 + 14.5f) / 6.0f));
    fp taud = dss * (1.0f - exp(-(initvalu_39 + 14.5f) / 6.0f)) / (0.035f * (initvalu_39 + 14.5f));
    fp fss = 1.0f / (1.0f + exp((initvalu_39 + 35.06f) / 3.6f)) + 0.6f / (1.0f + exp((50.0f - initvalu_39) / 20.0f));
    fp tauf = 1.0f / (0.0197f * exp(-pow(0.0337f * (initvalu_39 + 14.5f), 2.0f)) + 0.02f);
    finavalu[b + 3] = (dss - initvalu_4) / taud;
    finavalu[b + 4] = (fss - initvalu_5) / tauf;
    finavalu[b + 5] = 1.7f * initvalu_36 * (1.0f - initvalu_6) - 11.9e-3f * initvalu_6;
    finavalu[b + 6] = 1.7f * initvalu_37 * (1.0f - initvalu_7) - 11.9e-3f * initvalu_7;

    fp ibarca_j  = pCa * 4.0f * (initvalu_39 * Frdy * FoRT) * (0.341f * initvalu_36 * exp(2.0f * initvalu_39 * FoRT) - 0.341f * Cao) / (exp(2.0f * initvalu_39 * FoRT) - 1.0f);
    fp ibarca_sl = pCa * 4.0f * (initvalu_39 * Frdy * FoRT) * (0.341f * initvalu_37 * exp(2.0f * initvalu_39 * FoRT) - 0.341f * Cao) / (exp(2.0f * initvalu_39 * FoRT) - 1.0f);
    fp ibark     = pK  * (initvalu_39 * Frdy * FoRT) * (0.75f * initvalu_35 * exp(initvalu_39 * FoRT) - 0.75f * Ko) / (exp(initvalu_39 * FoRT) - 1.0f);
    fp ibarna_j  = pNa * (initvalu_39 * Frdy * FoRT) * (0.75f * initvalu_32 * exp(initvalu_39 * FoRT) - 0.75f * Nao) / (exp(initvalu_39 * FoRT) - 1.0f);
    fp ibarna_sl = pNa * (initvalu_39 * Frdy * FoRT) * (0.75f * initvalu_33 * exp(initvalu_39 * FoRT) - 0.75f * Nao) / (exp(initvalu_39 * FoRT) - 1.0f);

    fp I_Ca_junc = (Fjunc_CaL * ibarca_j  * initvalu_4 * initvalu_5 * (1.0f - initvalu_6) * pow(Q10CaL, Qpow)) * 0.45f;
    fp I_Ca_sl   = (Fsl_CaL   * ibarca_sl * initvalu_4 * initvalu_5 * (1.0f - initvalu_7) * pow(Q10CaL, Qpow)) * 0.45f;
    fp I_Ca = I_Ca_junc + I_Ca_sl;
    finavalu[b + 42] = -I_Ca * Cmem / (Vmyo * 2.0f * Frdy) * 1.0e3f;

    fp I_CaK = (ibark * initvalu_4 * initvalu_5 * (Fjunc_CaL * (1.0f - initvalu_6) + Fsl_CaL * (1.0f - initvalu_7)) * pow(Q10CaL, Qpow)) * 0.45f;
    fp I_CaNa_junc = (Fjunc_CaL * ibarna_j  * initvalu_4 * initvalu_5 * (1.0f - initvalu_6) * pow(Q10CaL, Qpow)) * 0.45f;
    fp I_CaNa_sl   = (Fsl_CaL   * ibarna_sl * initvalu_4 * initvalu_5 * (1.0f - initvalu_7) * pow(Q10CaL, Qpow)) * 0.45f;
    fp I_CaNa = I_CaNa_junc + I_CaNa_sl;
    fp I_Catot = I_Ca + I_CaK + I_CaNa;

    fp Ka_junc = 1.0f / (1.0f + pow(Kdact / initvalu_36, 3.0f));
    fp Ka_sl   = 1.0f / (1.0f + pow(Kdact / initvalu_37, 3.0f));
    fp s1_junc = exp(nu * initvalu_39 * FoRT) * cube(initvalu_32) * Cao;
    fp s1_sl   = exp(nu * initvalu_39 * FoRT) * cube(initvalu_33) * Cao;
    fp s2_junc = exp((nu - 1.0f) * initvalu_39 * FoRT) * cube(Nao) * initvalu_36;
    fp s3_junc = (KmCai * cube(Nao) * (1.0f + pow(initvalu_32 / KmNai, 3.0f))
                + cube(KmNao) * initvalu_36
                + cube(KmNai) * Cao * (1.0f + initvalu_36 / KmCai)
                + KmCao * cube(initvalu_32)
                + cube(initvalu_32) * Cao
                + cube(Nao) * initvalu_36) * (1.0f + ksat * exp((nu - 1.0f) * initvalu_39 * FoRT));
    fp s2_sl = exp((nu - 1.0f) * initvalu_39 * FoRT) * cube(Nao) * initvalu_37;
    fp s3_sl = (KmCai * cube(Nao) * (1.0f + pow(initvalu_33 / KmNai, 3.0f))
              + cube(KmNao) * initvalu_37
              + cube(KmNai) * Cao * (1.0f + initvalu_37 / KmCai)
              + KmCao * cube(initvalu_33)
              + cube(initvalu_33) * Cao
              + cube(Nao) * initvalu_37) * (1.0f + ksat * exp((nu - 1.0f) * initvalu_39 * FoRT));
    fp I_ncx_junc = Fjunc * IbarNCX * pow(Q10NCX, Qpow) * Ka_junc * (s1_junc - s2_junc) / s3_junc;
    fp I_ncx_sl   = Fsl   * IbarNCX * pow(Q10NCX, Qpow) * Ka_sl   * (s1_sl   - s2_sl)   / s3_sl;
    fp I_ncx = I_ncx_junc + I_ncx_sl;
    finavalu[b + 44] = 2.0f * I_ncx * Cmem / (Vmyo * 2.0f * Frdy) * 1.0e3f;

    fp I_pca_junc = Fjunc * pow(Q10SLCaP, Qpow) * IbarSLCaP * pow(initvalu_36, 1.6f) / (pow(KmPCa, 1.6f) + pow(initvalu_36, 1.6f));
    fp I_pca_sl   = Fsl   * pow(Q10SLCaP, Qpow) * IbarSLCaP * pow(initvalu_37, 1.6f) / (pow(KmPCa, 1.6f) + pow(initvalu_37, 1.6f));
    fp I_pca = I_pca_junc + I_pca_sl;
    finavalu[b + 43] = -I_pca * Cmem / (Vmyo * 2.0f * Frdy) * 1.0e3f;

    fp I_cabk_junc = Fjunc * GCaB * (initvalu_39 - eca_junc);
    fp I_cabk_sl   = Fsl   * GCaB * (initvalu_39 - eca_sl);
    fp I_cabk = I_cabk_junc + I_cabk_sl;
    finavalu[b + 45] = -I_cabk * Cmem / (Vmyo * 2.0f * Frdy) * 1.0e3f;

    fp MaxSR = 15.0f;
    fp MinSR = 1.0f;
    fp kCaSR = MaxSR - (MaxSR - MinSR) / (1.0f + pow(ec50SR / initvalu_31, 2.5f));
    fp koSRCa = koCa / kCaSR;
    fp kiSRCa = kiCa * kCaSR;
    fp RI = 1.0f - initvalu_14 - initvalu_15 - initvalu_16;
    finavalu[b + 13] = (kim * RI - kiSRCa * initvalu_36 * initvalu_14) - (koSRCa * sqr(initvalu_36) * initvalu_14 - kom * initvalu_15);
    finavalu[b + 14] = (koSRCa * sqr(initvalu_36) * initvalu_14 - kom * initvalu_15) - (kiSRCa * initvalu_36 * initvalu_15 - kim * initvalu_16);
    finavalu[b + 15] = (kiSRCa * initvalu_36 * initvalu_15 - kim * initvalu_16) - (kom * initvalu_16 - koSRCa * sqr(initvalu_36) * RI);
    fp J_SRCarel = ks * initvalu_15 * (initvalu_31 - initvalu_36);
    fp J_serca = pow(Q10SRCaP, Qpow) * Vmax_SRCaP * (pow(initvalu_38 / Kmf, hillSRCaP) - pow(initvalu_31 / Kmr, hillSRCaP))
               / (1.0f + pow(initvalu_38 / Kmf, hillSRCaP) + pow(initvalu_31 / Kmr, hillSRCaP));
    fp J_SRleak = 5.348e-6f * (initvalu_31 - initvalu_36);

    finavalu[b + 16] = kon_na * initvalu_32 * (Bmax_Naj  - initvalu_17) - koff_na * initvalu_17;
    finavalu[b + 17] = kon_na * initvalu_33 * (Bmax_Nasl - initvalu_18) - koff_na * initvalu_18;

    finavalu[b + 18] = kon_tncl * initvalu_38 * (Bmax_TnClow - initvalu_19) - koff_tncl * initvalu_19;
    finavalu[b + 19] = kon_tnchca * initvalu_38 * (Bmax_TnChigh - initvalu_20 - initvalu_21) - koff_tnchca * initvalu_20;
    finavalu[b + 20] = kon_tnchmg * Mgi * (Bmax_TnChigh - initvalu_20 - initvalu_21) - koff_tnchmg * initvalu_21;
    finavalu[b + 21] = 0.0f;
    finavalu[b + 22] = kon_myoca * initvalu_38 * (Bmax_myosin - initvalu_23 - initvalu_24) - koff_myoca * initvalu_23;
    finavalu[b + 23] = kon_myomg * Mgi * (Bmax_myosin - initvalu_23 - initvalu_24) - koff_myomg * initvalu_24;
    finavalu[b + 24] = kon_sr * initvalu_38 * (Bmax_SR - initvalu_25) - koff_sr * initvalu_25;
    fp J_CaB_cytosol = finavalu[b + 18] + finavalu[b + 19] + finavalu[b + 20] + finavalu[b + 21] + finavalu[b + 22] + finavalu[b + 23] + finavalu[b + 24];

    finavalu[b + 25] = kon_sll * initvalu_36 * (Bmax_SLlowj  - initvalu_26) - koff_sll * initvalu_26;
    finavalu[b + 26] = kon_sll * initvalu_37 * (Bmax_SLlowsl - initvalu_27) - koff_sll * initvalu_27;
    finavalu[b + 27] = kon_slh * initvalu_36 * (Bmax_SLhighj  - initvalu_28) - koff_slh * initvalu_28;
    finavalu[b + 28] = kon_slh * initvalu_37 * (Bmax_SLhighsl - initvalu_29) - koff_slh * initvalu_29;
    fp J_CaB_junction = finavalu[b + 25] + finavalu[b + 27];
    fp J_CaB_sl = finavalu[b + 26] + finavalu[b + 28];

    finavalu[b + 29] = kon_csqn * initvalu_31 * (Bmax_Csqn - initvalu_30) - koff_csqn * initvalu_30;
    fp oneovervsr = 1.0f / Vsr;
    finavalu[b + 30] = J_serca * Vmyo * oneovervsr - (J_SRleak * Vmyo * oneovervsr + J_SRCarel) - finavalu[b + 29];

    fp I_Na_tot_junc = I_Na_junc + I_nabk_junc + 3.0f * I_ncx_junc + 3.0f * I_nak_junc + I_CaNa_junc;
    fp I_Na_tot_sl   = I_Na_sl   + I_nabk_sl   + 3.0f * I_ncx_sl   + 3.0f * I_nak_sl   + I_CaNa_sl;
    finavalu[b + 31] = -I_Na_tot_junc * Cmem / (Vjunc * Frdy) + J_na_juncsl / Vjunc * (initvalu_33 - initvalu_32) - finavalu[b + 16];
    fp oneovervsl = 1.0f / Vsl;
    finavalu[b + 32] = -I_Na_tot_sl * Cmem * oneovervsl / Frdy + J_na_juncsl * oneovervsl * (initvalu_32 - initvalu_33) + J_na_slmyo * oneovervsl * (initvalu_34 - initvalu_33) - finavalu[b + 17];
    finavalu[b + 33] = J_na_slmyo / Vmyo * (initvalu_33 - initvalu_34);

    fp I_K_tot = I_to + I_kr + I_ks + I_ki - 2.0f * I_nak + I_CaK + I_kp;
    finavalu[b + 34] = 0.0f;

    fp I_Ca_tot_junc = I_Ca_junc + I_cabk_junc + I_pca_junc - 2.0f * I_ncx_junc;
    fp I_Ca_tot_sl   = I_Ca_sl   + I_cabk_sl   + I_pca_sl   - 2.0f * I_ncx_sl;
    finavalu[b + 35] = -I_Ca_tot_junc * Cmem / (Vjunc * 2.0f * Frdy) + J_ca_juncsl / Vjunc * (initvalu_37 - initvalu_36)
                     - J_CaB_junction + J_SRCarel * Vsr / Vjunc + J_SRleak * Vmyo / Vjunc;
    finavalu[b + 36] = -I_Ca_tot_sl * Cmem / (Vsl * 2.0f * Frdy) + J_ca_juncsl / Vsl * (initvalu_36 - initvalu_37)
                     + J_ca_slmyo / Vsl * (initvalu_38 - initvalu_37) - J_CaB_sl;
    finavalu[b + 37] = -J_serca - J_CaB_cytosol + J_ca_slmyo / Vmyo * (initvalu_37 - initvalu_38);

    fp junc_sl = J_ca_juncsl / Vsl * (initvalu_36 - initvalu_37);
    fp sl_junc = J_ca_juncsl / Vjunc * (initvalu_37 - initvalu_36);
    fp sl_myo  = J_ca_slmyo / Vsl * (initvalu_38 - initvalu_37);
    fp myo_sl  = J_ca_slmyo / Vmyo * (initvalu_37 - initvalu_38);

    int state = 1;
    fp I_app = 0.0f;
    fp V_hold, V_test, V_clamp, R_clamp;

    switch (state) {
        case 0:
            I_app = 0.0f;
            break;
        case 1:
            if (fmod(timeinst, parameter_1) <= 5.0f) {
                I_app = 9.5f;
            } else {
                I_app = 0.0f;
            }
            break;
        case 2:
            V_hold = -55.0f;
            V_test = 0.0f;
            if ((timeinst > 0.5f) & (timeinst < 200.5f)) {
                V_clamp = V_test;
            } else {
                V_clamp = V_hold;
            }
            R_clamp = 0.04f;
            I_app = (V_clamp - initvalu_39) / R_clamp;
            break;
    }

    fp I_Na_tot = I_Na_tot_junc + I_Na_tot_sl;
    fp I_Cl_tot = I_ClCa + I_Clbk;
    fp I_Ca_tot = I_Ca_tot_junc + I_Ca_tot_sl;
    fp I_tot = I_Na_tot + I_Cl_tot + I_Ca_tot + I_K_tot;
    finavalu[b + 38] = -(I_tot - I_app);

    finavalu[b + 40] = 0.0f;
    finavalu[b + 41] = 0.0f;

    (void)distSLcyto;
    (void)distJuncSL;
    (void)DcaJuncSL;
    (void)DcaSLcyto;
    (void)DnaJuncSL;
    (void)DnaSLcyto;
    (void)SAjunc;
    (void)SAsl;
    (void)Q10NaK;
    (void)Q10KmNai;
    (void)KmCa;
    (void)Bmax_CaM;
    (void)koff_cam;
    (void)kon_cam;
    (void)initvalu_41;
    (void)initvalu_42;
    (void)initvalu_43;
    (void)initvalu_44;
    (void)initvalu_45;
    (void)initvalu_46;
    (void)I_Na;
    (void)I_nabk;
    (void)I_nak;
    (void)I_Catot;
    (void)junc_sl;
    (void)sl_junc;
    (void)sl_myo;
    (void)myo_sl;
}

__kernel void kernel_gpu_opencl(fp timeinst,
                                __global const fp *initvalu,
                                __global fp *finavalu,
                                __global const fp *parameter,
                                __global fp *com)
{
    int gid = get_global_id(0);

    if (gid == 0) {
        kernel_ecc(timeinst, initvalu, 0, parameter, 0, finavalu);
    } else if (gid == 1) {
        com[0] = kernel_cam(timeinst, initvalu, 46, parameter, 1, finavalu, initvalu[35] * 1.0e3f);
    } else if (gid == 2) {
        com[1] = kernel_cam(timeinst, initvalu, 61, parameter, 6, finavalu, initvalu[36] * 1.0e3f);
    } else if (gid == 3) {
        com[2] = kernel_cam(timeinst, initvalu, 76, parameter, 11, finavalu, initvalu[37] * 1.0e3f);
    }
}
